INSERT INTO cities (county_id, name, slug, latitude, longitude, population) VALUES ((SELECT id FROM counties WHERE slug = 'nueces-county' AND state_id = (SELECT id FROM states WHERE slug = 'texas')), 'Corpus Christi', 'corpus-christi', 27.8006, -97.3964, 317863) ON CONFLICT (county_id, slug) DO UPDATE SET latitude = excluded.latitude, longitude = excluded.longitude, population = excluded.population;
