INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'corpus-christi'), 'FR', 'fr', 'Farm Rural District', 'The Farm Rural zoning district includes lands that are relatively underdeveloped and agricultural in nature, intended to permit the continued use of the land for agricultural purposes. It serves as the default zoning for newly-annexed land not yet assigned a final zoning classification.', 35, NULL, 43560, 50, 40, 25, 10, 'Two (2) paved off-street parking spaces per dwelling unit on the same lot.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'fr' AND z.city_id = (SELECT id FROM cities WHERE slug = 'corpus-christi') AND pu.name IN ('Single-family detached dwellings', 'Agricultural uses', 'Accessory buildings') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'corpus-christi'), 'RE', 're', 'Residential Estate District', 'The Residential Estate zoning district provides for single-family residential development of a spacious character with related recreational facilities, aiming to create an orderly, attractive, and spacious residential living environment. Lots are a minimum of 1 acre and are not intended to be served by City water, wastewater, or stormwater services, retaining a rural character.', 35, NULL, 43560, 50, 30, 20, 10, 'Two (2) paved off-street parking spaces per dwelling unit on the same lot.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 're' AND z.city_id = (SELECT id FROM cities WHERE slug = 'corpus-christi') AND pu.name IN ('Single-family detached dwellings', 'Related recreational facilities', 'Accessory buildings') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'corpus-christi'), 'RS-6', 'rs-6', 'Single-Family 6 District', 'The Single-Family 6 zoning district provides for orderly suburban residential development and redevelopment, allowing a limited number of public and civic uses to preserve the single-family character of the neighborhood. The numerical value relates to the minimum lot size.', 35, NULL, 6000, 50, 25, 20, 5, 'Two (2) paved off-street parking spaces per dwelling unit on the same lot.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
