INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'corpus-christi'), 'RS-TH', 'rs-th', 'Townhouse District', 'The Townhouse zoning district allows for smaller dwelling units than typically found in single-family districts, suitable for infill development and as a transition area between residential and nonresidential zones. Townhouse developments may be platted as fee-simple lots or condominiums.', 35, NULL, NULL, 50, 20, 20, 5, 'Two (2) paved off-street parking spaces plus a one-car garage for each dwelling unit on the same lot.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
