INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'corpus-christi'), 'RM-1', 'rm-1', 'Multifamily 1 District', 'The Multifamily 1 zoning district provides for a variety of housing types at multifamily densities, appropriate for areas with convenient access to collector and arterial streets, and nearby civic, commercial, and employment opportunities.', 35, NULL, NULL, NULL, 25, 20, 10, '1.5 spaces per 0/1 bedroom unit, 2.0 spaces per 2 bedroom unit, 2.5 spaces per 3+ bedroom unit; average of not less than 2 spaces per unit for total development.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'rm-1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'corpus-christi') AND pu.name IN ('Single-family detached dwellings', 'Two-family dwellings', 'Townhouse units', 'Apartment units') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'corpus-christi'), 'CH', 'ch', 'Cottage Housing District', 'The Cottage Housing District promotes a traditional neighborhood development pattern to maintain and enhance existing small-city character, creating small communities of cottages around common open space. It allows for higher residential density than typical single-family zones through smaller homes, reduced setbacks, and clustered parking.', NULL, NULL, 21780, 65, 10, 5, 0, '1.25 spaces per unit for dwellings under 1,000 sq ft; 1.5 spaces per unit for dwellings 1,000-1,400 sq ft.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
