INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'corpus-christi'), 'CN-1', 'cn-1', 'Neighborhood Commercial 1 District', 'The Neighborhood Commercial 1 zoning district provides areas for commercial activity, such as convenience goods and personal services, that primarily benefit nearby residential areas. These areas are generally located within neighborhoods with pedestrian access to adjacent residential areas.', 35, NULL, NULL, NULL, 25, 10, 5, 'One (1) parking space for each 200 square feet of floor area, with a minimum of 3 spaces.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
