INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'corpus-christi'), 'IL', 'il', 'Light Industrial District', 'The Light Industrial zoning district accommodates light manufacturing, fabricating, warehousing, and wholesale distributing in buildings with access by major arterials, freeways, or railroads. Uses are limited to those not objectionable by reason of odor, dust, smoke, noise, or vibration.', 100, NULL, 5000, 90, 25, 5, 5, 'One (1) space per 500 sq ft of floor area for manufacturing/research; one (1) space per 1,000 sq ft for warehouses.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
